public void testTurkishLocaleSpecificCases() {
    Locale orig = Locale.getDefault();
    try {
        Locale.setDefault(new Locale("tr"));
        CaseInsensitiveMap map = new CaseInsensitiveMap();

        // Turkish-specific lowercase conversion: 'I' -> 'ı' (dotless i)
        // In English: 'I' -> 'i' (regular i)
        // The map should use English locale for consistency
        map.put("I", "capital_I");

        // Should retrieve with lowercase 'i' (English conversion)
        assertEquals("Should find 'I' with lowercase 'i'", "capital_I", map.get("i"));

        // Turkish uppercase 'İ' (capital i with dot)
        map.put("\u0130", "capital_I_with_dot");

        // Should retrieve with lowercase (English conversion of İ)
        assertEquals("Should find capital İ with lowercase", "capital_I_with_dot", map.get("\u0130".toLowerCase(Locale.ENGLISH)));
    } finally {
        Locale.setDefault(orig);
    }
}

public void testGreekSigmaVariants() {
    CaseInsensitiveMap map = new CaseInsensitiveMap();

    // Greek capital sigma: Σ (U+03A3)
    // Greek small sigma: σ (U+03C3)
    // Greek small final sigma: ς (U+03C2)
    // All three should map to the same key

    map.put("\u03A3", "capital_sigma");

    // Should be able to retrieve with lowercase sigma
    assertEquals("Should find Σ with σ", "capital_sigma", map.get("\u03C3"));

    // Should be able to retrieve with final sigma
    assertEquals("Should find Σ with ς", "capital_sigma", map.get("\u03C2"));

    // Test reverse: put with lowercase, get with uppercase
    map.clear();
    map.put("\u03C3", "lowercase_sigma");
    assertEquals("Should find σ with Σ", "lowercase_sigma", map.get("\u03A3"));

    // Put with final sigma, get with regular sigma
    map.clear();
    map.put("\u03C2", "final_sigma");
    assertEquals("Should find ς with σ", "final_sigma", map.get("\u03C3"));
}

public void testNullKeyHandling() {
    CaseInsensitiveMap map = new CaseInsensitiveMap();

    // Test null key behavior
    map.put(null, "null_value");
    assertEquals("Should retrieve value for null key", "null_value", map.get(null));

    // Test that null is treated consistently
    assertTrue("Map should contain null key", map.containsKey(null));

    // Overwrite null key
    map.put(null, "new_null_value");
    assertEquals("Should retrieve updated value for null key", "new_null_value", map.get(null));
    assertEquals("Map should have size 1 after overwriting null", 1, map.size());
}
